{"code": "import json
import re
from collections import defaultdict

# Get the data
data_key = 'var_functions.query_db:30'
wifi_businesses = globals().get(data_key, [])

print(f'Query returned {len(wifi_businesses)} businesses')

# Look for additional MongoDB results if this is just a preview
# Let's check the storage key format
for key in list(globals().keys()):
    if 'query_db' in key:
        print(f'Storage key: {key}')

wifi_count_by_state = defaultdict(int)
for business in wifi_businesses:
    desc = business.get('description', '')
    if not desc:
        continue
    m = re.search(r',\s*([A-Z]{2})\s*,', desc)
    if m:
        state = m.group(1)
        wifi = business.get('attributes', {}).get('WiFi', '')
        s = str(wifi).lower()
        if wifi and 'no' not in s:
            wifi_count_by_state[state] += 1

print(f'States found: {len(wifi_count_by_state)}')
for state, cnt in sorted(wifi_count_by_state.items(), key=lambda x: x[1], reverse=True):
    print(f'  {state}: {cnt}')

if wifi_count_by_state:
    top = max(wifi_count_by_state.items(), key=lambda x: x[1])
    result = {'top_state': top[0], 'count': top[1], 'all_states': dict(wifi_count_by_state)}
else:
    result = {'error': 'none'}

print('__RESULT__:')
print(json.dumps(result))"}

